{"action":"opened","issue":{"url":"https://api.github.com/repos/jump-dev/JuMP.jl/issues/3788","repository_url":"https://api.github.com/repos/jump-dev/JuMP.jl","labels_url":"https://api.github.com/repos/jump-dev/JuMP.jl/issues/3788/labels{/name}","comments_url":"https://api.github.com/repos/jump-dev/JuMP.jl/issues/3788/comments","events_url":"https://api.github.com/repos/jump-dev/JuMP.jl/issues/3788/events","html_url":"https://github.com/jump-dev/JuMP.jl/issues/3788","id":2432597716,"node_id":"I_kwDOAF3Xtc6Q_n7U","number":3788,"title":"Incorrect dual variable extracted from equality constraint between Hermitian matrices","user":{"login":"araujoms","id":997998,"node_id":"MDQ6VXNlcjk5Nzk5OA==","avatar_url":"https://avatars.githubusercontent.com/u/997998?v=4","gravatar_id":"","url":"https://api.github.com/users/araujoms","html_url":"https://github.com/araujoms","followers_url":"https://api.github.com/users/araujoms/followers","following_url":"https://api.github.com/users/araujoms/following{/other_user}","gists_url":"https://api.github.com/users/araujoms/gists{/gist_id}","starred_url":"https://api.github.com/users/araujoms/starred{/owner}{/repo}","subscriptions_url":"https://api.github.com/users/araujoms/subscriptions","organizations_url":"https://api.github.com/users/araujoms/orgs","repos_url":"https://api.github.com/users/araujoms/repos","events_url":"https://api.github.com/users/araujoms/events{/privacy}","received_events_url":"https://api.github.com/users/araujoms/received_events","type":"User","site_admin":false},"labels":[],"state":"open","locked":false,"assignee":null,"assignees":[],"milestone":null,"comments":0,"created_at":"2024-07-26T16:47:17Z","updated_at":"2024-07-26T16:47:17Z","closed_at":null,"author_association":"CONTRIBUTOR","active_lock_reason":null,"body":"When I use a constraint of the form `@constraint(model, A == B)`, where `A` and `B` are Hermitian matrices, for some reason the dual variable associated to this constraint has the off-diagonal elements multiplied by 2. I've tested a couple of different solvers, so the bug must be inside JuMP itself. A MWE follows below. Note the text-to-last line, where I'm dividing the off-diagonal elements of the dual variable by 2 to make it match the primal result.

```julia

using JuMP
using LinearAlgebra
import Hypatia
import Clarabel
import Ket
import Random

function dual_test(d)
    Random.seed!(1)
    ρ = Ket.random_state(d^2, 1)

    model = Model()
    @variable(model, σ[1:d^2, 1:d^2] in HermitianPSDCone())
    @variable(model, λ)
    noisy_state = Hermitian(ρ + λ * I(d^2))
    @constraint(model, witness_constraint, σ == noisy_state)
    @objective(model, Min, λ)
    @constraint(model, Ket.partial_transpose(σ, 2, [d, d]) in HermitianPSDCone())

    set_optimizer(model, Hypatia.Optimizer)
    #set_optimizer(model, Clarabel.Optimizer)
    optimize!(model)

    W = dual(witness_constraint)
    W = Hermitian(Diagonal(W) + 0.5(W - Diagonal(W))) #workaround
    return objective_value(model), dot(ρ, W)
end
