{"action":"opened","issue":{"url":"https://api.github.com/repos/jump-dev/JuMP.jl/issues/3286","repository_url":"https://api.github.com/repos/jump-dev/JuMP.jl","labels_url":"https://api.github.com/repos/jump-dev/JuMP.jl/issues/3286/labels{/name}","comments_url":"https://api.github.com/repos/jump-dev/JuMP.jl/issues/3286/comments","events_url":"https://api.github.com/repos/jump-dev/JuMP.jl/issues/3286/events","html_url":"https://github.com/jump-dev/JuMP.jl/issues/3286","id":1627067965,"node_id":"I_kwDOAF3Xtc5g-xY9","number":3286,"title":"Poor performance with complex SDPs","user":{"login":"araujoms","id":997998,"node_id":"MDQ6VXNlcjk5Nzk5OA==","avatar_url":"https://avatars.githubusercontent.com/u/997998?v=4","gravatar_id":"","url":"https://api.github.com/users/araujoms","html_url":"https://github.com/araujoms","followers_url":"https://api.github.com/users/araujoms/followers","following_url":"https://api.github.com/users/araujoms/following{/other_user}","gists_url":"https://api.github.com/users/araujoms/gists{/gist_id}","starred_url":"https://api.github.com/users/araujoms/starred{/owner}{/repo}","subscriptions_url":"https://api.github.com/users/araujoms/subscriptions","organizations_url":"https://api.github.com/users/araujoms/orgs","repos_url":"https://api.github.com/users/araujoms/repos","events_url":"https://api.github.com/users/araujoms/events{/privacy}","received_events_url":"https://api.github.com/users/araujoms/received_events","type":"User","site_admin":false},"labels":[],"state":"open","locked":false,"assignee":null,"assignees":[],"milestone":null,"comments":0,"created_at":"2023-03-16T09:39:23Z","updated_at":"2023-03-16T09:39:23Z","closed_at":null,"author_association":"NONE","active_lock_reason":null,"body":"The generated SDP is very inefficient when using HermitianPSDCone constraints. For example, in the state discrimination SDP below, JuMP generates 2d + 4d^2 constraints and 2 + 2d + 11d^2 variables, whereas YALMIP needs only 2d^2 constraints and 2 + 9d^2 variables. When restricting to real numbers both JuMP and YALMIP generated exactly the same SDP, so the problem is really only with complex variables.

The JuMP code is
```
using JuMP
using LinearAlgebra
import SeDuMi

function random_state(d)
    x = randn(ComplexF64, (d,d))
    y = x*x'
    rho = Hermitian(y/tr(y))
    return rho
end


function discriminate(d)
    model = Model(SeDuMi.Optimizer)
    rho1 = random_state(d)
    rho2 = random_state(d)
    E1 = @variable(model, [1:d, 1:d] in HermitianPSDCone())
    E2 = @variable(model, [1:d, 1:d] in HermitianPSDCone())
    @constraint(model, E1+E2 == I)
    obj = real(dot(rho1,E1) + dot(rho2,E2))/2
    @objective(model, Max, obj)
    optimize!(model)
    print(value(obj),"\n\n")

    #analytical answer for debugging
    print(0.5 + 0.25*sum(svdvals(rho1-rho2)))
    return
end
```
and the YALMP code is
```
function discriminate(d)

    rho1 = random_state(d);
    rho2 = random_state(d);
    E1 = sdpvar(d,d,'hermitian','complex');
    E2 = sdpvar(d,d,'hermitian','complex');

    objective = real(rho1(:)'*E1(:) + rho2(:)'*E2(:));

    constraints = [E1 >= 0, E2 >= 0];
    id=eye(d);
    for i=1:d
        for j=i:d
            constraints = [constraints, E1(i,j) + E2(i,j) == id(i,j)];
        end
    end

    ops = sdpsettings(sdpsettings,'verbose',1,'solver','sedumi');
    sol = optimize(constraints,-objective,ops);
    objective = value(objective)

    %compute the probability of discrimination via the analytical formula
    2*(0.5 + 0.25*sum(svd(rho1-rho2)))    

end

function rho = random_state(d)

    x = randn(d,d) + 1i*randn(d,d);
    y = x*x';
    rho = y/trace(y);

end
```
Note that to reproduce the YALMIP results you need to use an older version, in the latest git I have added support for using complex numbers natively, so the performance is even better.
